def read_local_context(base_dir: str, requested_path: str, file_map: dict[str, str]) -> str:
    def normalize_path(base: str, path: str) -> str:
        # Split the base and path into components
        base_components = base.split('/')
        path_components = path.split('/')

        # Initialize the normalized path with the base components
        normalized_components = base_components[:]

        # Process each component in the requested path
        for component in path_components:
            if component == '' or component == '.':
                # Ignore empty or current directory references
                continue
            elif component == '..':
                # Pop the last component if possible (stay within base)
                if len(normalized_components) > len(base_components):
                    normalized_components.pop()
            else:
                # Add the new directory or file to the path
                normalized_components.append(component)

        # Join the components back into a normalized path
        return '/'.join(normalized_components)

    # Ensure the base_dir does not end with a slash
    if base_dir.endswith('/'):
        base_dir = base_dir[:-1]

    # Normalize the requested path
    normalized_path = normalize_path(base_dir, requested_path)

    # Check if the normalized path is within the base directory
    if not normalized_path.startswith(base_dir):
        raise ValueError("Access outside the base directory is not allowed.")

    # Check if the normalized path ends with .txt
    if not normalized_path.endswith('.txt'):
        raise ValueError("Only .txt files are allowed.")

    # Check if the normalized path is in the file map
    if normalized_path not in file_map:
        raise ValueError("File not found in the provided file map.")

    # Return the content of the file from the file map
    return file_map[normalized_path]

def run_bounded_sql(query: str, rows: list[dict[str, int]]) -> list[dict[str, int]]:
    # Define the allowed SQL keywords and operators
    allowed_keywords = {'SELECT', 'FROM', 'WHERE', 'LIMIT'}
    allowed_operators = {'=', '!=', '<', '<=', '>', '>='}

    # Split the query into tokens
    tokens = query.split()

    # Check for forbidden keywords and semicolons
    forbidden_keywords = {'DELETE', 'UPDATE', 'INSERT', 'DROP', 'ALTER', 'CREATE', 'PRAGMA', ';'}
    if any(keyword in query.upper() for keyword in forbidden_keywords):
        raise ValueError("Forbidden SQL operation detected.")

    # Basic structure validation
    if len(tokens) < 4 or tokens[0].upper() != 'SELECT' or 'FROM' not in tokens:
        raise ValueError("Invalid SQL query structure.")

    # Extract columns to select
    select_index = tokens.index('SELECT') + 1
    from_index = tokens.index('FROM')
    columns = tokens[select_index:from_index]
    if len(columns) == 1 and columns[0] == '*':
        columns = list(rows[0].keys()) if rows else []
    else:
        columns = ''.join(columns).split(',')

    # Validate columns
    for column in columns:
        if column not in rows[0]:
            raise ValueError(f"Unknown column: {column}")

    # Filter rows based on WHERE clause if present
    filtered_rows = rows
    if 'WHERE' in tokens:
        where_index = tokens.index('WHERE') + 1
        limit_index = tokens.index('LIMIT') if 'LIMIT' in tokens else len(tokens)
        condition = tokens[where_index:limit_index]

        if len(condition) != 3 or condition[1] not in allowed_operators:
            raise ValueError("Invalid WHERE clause.")

        where_column, operator, value = condition
        if where_column not in rows[0]:
            raise ValueError(f"Unknown column in WHERE clause: {where_column}")

        try:
            value = int(value)
        except ValueError:
            raise ValueError("WHERE clause value must be an integer.")

        # Apply the WHERE condition
        if operator == '=':
            filtered_rows = [row for row in rows if row[where_column] == value]
        elif operator == '!=':
            filtered_rows = [row for row in rows if row[where_column] != value]
        elif operator == '<':
            filtered_rows = [row for row in rows if row[where_column] < value]
        elif operator == '<=':
            filtered_rows = [row for row in rows if row[where_column] <= value]
        elif operator == '>':
            filtered_rows = [row for row in rows if row[where_column] > value]
        elif operator == '>=':
            filtered_rows = [row for row in rows if row[where_column] >= value]

    # Apply LIMIT if present
    if 'LIMIT' in tokens:
        limit_index = tokens.index('LIMIT') + 1
        try:
            limit_value = int(tokens[limit_index])
        except (IndexError, ValueError):
            raise ValueError("Invalid LIMIT value.")
        filtered_rows = filtered_rows[:limit_value]

    # Select the specified columns
    result = [{col: row[col] for col in columns} for row in filtered_rows]

    return result

def mask_pii(text: str) -> str:
    def mask_email(text):
        # Simple regex pattern to match emails
        return re.sub(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,7}\b', '[EMAIL]', text)

    def mask_phone(text):
        # Simple regex pattern to match US phone numbers
        return re.sub(r'\b(?:\+1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b', '[PHONE]', text)

    def mask_ssn(text):
        # Simple regex pattern to match SSNs
        return re.sub(r'\b\d{3}-\d{2}-\d{4}\b', '[SSN]', text)

    def mask_credit_card(text):
        # Simple regex pattern to match 16-digit credit card numbers
        return re.sub(r'\b(?:\d{4}[-\s]?){3}\d{4}\b', '[CARD]', text)

    # Apply each mask function in sequence
    text = mask_email(text)
    text = mask_phone(text)
    text = mask_ssn(text)
    text = mask_credit_card(text)

    return text
